class Solution {
    public int bestClosingTime(String customers) {
        int n = customers.length();
        int[] countY = new int[n];
        int[] countN = new int[n];

        for (int i = 0; i < n; i++) {
            if (customers.charAt(i) == 'Y') {
                countY[i]++;
            } else if (customers.charAt(i) == 'N') {
                countN[i]--;
            }
        }

        int minPenalty = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            if (countY[i] == 0 && countN[i] == 0) {
                minPenalty = Math.min(minPenalty, i + 1);
            }
        }

        return minPenalty;
    }
}
